type PlanNode = { plugin: string; demographicWeight: number };

class PlannerFairnessAuditor {
  auditPlan(plan: PlanNode[]): number {
    const demographicVariance = plan
      .map(node => node.demographicWeight)
      .reduce((varSum, weight, i, arr) => {
        const mean = arr.reduce((a, b) => a + b) / arr.length;
        return varSum + Math.pow(weight - mean, 2);
      }, 0) / plan.length;

    return demographicVariance > 0.3 ? 1 : 0; // Flag unfair plans
  }
}

