import { ActionPlanner } from '@semantic-kernel/agents';

class FairnessAwarePlanner extends ActionPlanner {
  async createPlan(
    goal: string,
    functions: Function[],
    config?: PlannerConfig
  ): Promise<Plan> {
    const plans = await super.createPlan(goal, functions, config);

    // Select plan with highest fairness score
    const fairPlans = plans.map(plan => ({
      ...plan,
      fairnessScore: this.calculateFairnessScore(plan),
    }));

    return fairPlans.sort((a, b) => 
      b.fairnessScore - a.fairnessScore
    )[0];
  }

  private calculateFairnessScore(plan: Plan): number {
    return plan.functions.reduce((score, func) => {
      return score + (func.metadata?.fairnessWeight || 0.5);
    }, 0) / plan.functions.length;
  }
}
