from semantic_kernel.memory import SemanticTextMemory
import numpy as np

class DebaisedMemory(SemanticTextMemory):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.fairness_weights = self.compute_fairness_weights()

    def search(self, query, limit=10, min_relevance_score=0.7):
        results = super().search(query, limit, min_relevance_score)

        # Reweight by fairness
        weighted_results = []
        for result in results:
            weight = self.fairness_weights.get(result.id, 1.0)
            weighted_results.append({
                **result,
                relevance_score: result.relevance_score * weight
            })

        return sorted(weighted_results, 
                     key=lambda x: x['relevance_score'], 
                     reverse=True)[:limit]
